class HalfEdge:
    def __init__(self, vertex, face):
        self.vertex = vertex      # Starting vertex
        self.face = face           # Face this half-edge belongs to
        self.opposite = None       # Opposite half-edge
        self.next = None           # Next half-edge around face

class Vertex:
    def __init__(self, x, y, z):
        self.position = (x, y, z)
        self.halfedge = None       # One incident half-edge

class Face:
    def __init__(self):
        self.halfedge = None       # One half-edge on face boundary

def traverse_face(face):
    """Traverse all vertices around a face"""
    vertices = []
    he = face.halfedge

    while True:
        vertices.append(he.vertex.position)
        he = he.next
        if he == face.halfedge:
            break

    return vertices

def get_adjacent_face(face):
    """Get face adjacent across an edge"""
    he = face.halfedge
    return he.opposite.face

