// Example on 1 quad (4 vertices):
// Original: V1, V2, V3, V4
// After subdivision: 4 new quads
// Each quad uses: 1 original vertex, 2 edge points, 1 face point

#include <stdio.h>
#include <stdlib.h>

typedef struct Vertex {
    int id;
    float x, y, z;
    struct Vertex** neighbors;  // Adjacent vertices
    int neighborCount;
} Vertex;

typedef struct Mesh {
    Vertex* vertices;
    int vertexCount;
    int** adjacencyMatrix;
} Mesh;

// Build adjacency list from face definitions
void buildAdjacencyList(Mesh* mesh, int faces[][4], int faceCount) {
    // Initialize neighbor arrays
    for (int i = 0; i < mesh->vertexCount; i++) {
        mesh->vertices[i].neighbors = NULL;
        mesh->vertices[i].neighborCount = 0;
    }

    // For each face, connect all vertices
    for (int f = 0; f < faceCount; f++) {
        for (int i = 0; i < 4; i++) {
            int v1 = faces[f][i];
            int v2 = faces[f][(i + 1) % 4];  // Next vertex

            // Check if already connected
            int connected = 0;
            for (int j = 0; j < mesh->vertices[v1].neighborCount; j++) {
                if (mesh->vertices[v1].neighbors[j]->id == v2)
                    connected = 1;
            }

            if (!connected) {
                // Add v2 to v1's neighbor list
                mesh->vertices[v1].neighbors = realloc(
                    mesh->vertices[v1].neighbors,
                    (mesh->vertices[v1].neighborCount + 1) * sizeof(Vertex*)
                );
                mesh->vertices[v1].neighbors[mesh->vertices[v1].neighborCount++] = &mesh->vertices[v2];
            }
        }
    }
}

// Get all vertices adjacent to a vertex
void getVertexNeighbors(Vertex* v, Vertex** result, int* count) {
    *count = v->neighborCount;
    for (int i = 0; i < v->neighborCount; i++) {
        result[i] = v->neighbors[i];
    }
}
